// Handler emulates a search engine for the infinite content generated by the
// glitch server. Results are deterministic: the same query always produces the
// same titles, snippets, URLs, and result count.
type Handler struct {
	topics     []string
	adjectives []string
	nouns      []string
	verbs      []string
	sites      []string
	typos      map[string]string
	fileTypes  []string
}

