// ShouldHandle returns true for search-related endpoints.
func (h *Handler) ShouldHandle(path string) bool {
	return path == "/search" ||
		path == "/search/" ||
		path == "/search/advanced" ||
		path == "/search/images" ||
		path == "/api/search/suggest" ||
		strings.HasPrefix(path, "/search?")
}

// ServeHTTP dispatches to the appropriate search endpoint and returns the
// HTTP status code written to the response.
func (h *Handler) ServeHTTP(w http.ResponseWriter, r *http.Request) int {
	switch r.URL.Path {
	case "/search", "/search/":
		return h.serveResults(w, r)
	case "/search/advanced":
		return h.serveAdvanced(w, r)
	case "/search/images":
		return h.serveImages(w, r)
	case "/api/search/suggest":
		return h.serveSuggest(w, r)
	default:
		http.NotFound(w, r)
		return http.StatusNotFound
	}
}

// ---------------------------------------------------------------------------
// seed helpers
// ---------------------------------------------------------------------------

func querySeed(query string) int64 {
	h := sha256.Sum256([]byte(query))
	return int64(binary.BigEndian.Uint64(h[:8]))
}

func queryPageSeed(query string, page int) int64 {
	h := sha256.Sum256([]byte(fmt.Sprintf("%s:page:%d", query, page)))
	return int64(binary.BigEndian.Uint64(h[:8]))
}

// ---------------------------------------------------------------------------
// GET /search — main results page
// ---------------------------------------------------------------------------

func (h *Handler) serveResults(w http.ResponseWriter, r *http.Request) int {
	query := r.URL.Query().Get("q")
	if query == "" {
		return h.serveSearchHome(w)
	}

	pageStr := r.URL.Query().Get("page")
	page := 1
	if pageStr != "" {
		if n := atoi(pageStr); n > 0 {
			page = n
		}
	}

	rng := rand.New(rand.NewSource(querySeed(query)))

	// Deterministic total result count (10K - 10M)
	totalResults := rng.Intn(10_000_000-10_000) + 10_000
	// Deterministic search time
	searchTime := float64(rng.Intn(800)+50) / 1000.0

	// Generate 10 results for this page
	pageRng := rand.New(rand.NewSource(queryPageSeed(query, page)))
	results := h.generateResults(pageRng, query, 10)

	// Did-you-mean suggestion
	didYouMean := h.checkDidYouMean(query)

	// Total pages
	totalPages := (totalResults + 9) / 10
	if totalPages > 100 {
		totalPages = 100 // cap displayed pages
	}

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.WriteHeader(http.StatusOK)

	var sb strings.Builder

	sb.WriteString(`<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>`)
	htmlEscape(&sb, query)
	sb.WriteString(` - GlitchSearch</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { font-family: Arial, sans-serif; background: #fff; color: #202124; }
    .header { background: #fff; border-bottom: 1px solid #dfe1e5; padding: 20px 0 0 0; }
    .header-inner { max-width: 750px; margin-left: 150px; }
    .logo { font-size: 22px; font-weight: bold; color: #4285f4; text-decoration: none; margin-right: 24px; }
    .logo span:nth-child(1) { color: #4285f4; }
    .logo span:nth-child(2) { color: #ea4335; }
    .logo span:nth-child(3) { color: #fbbc05; }
    .logo span:nth-child(4) { color: #4285f4; }
    .logo span:nth-child(5) { color: #34a853; }
    .logo span:nth-child(6) { color: #ea4335; }
    .search-bar { display: flex; align-items: center; margin: 16px 0; }
    .search-input { width: 600px; padding: 10px 16px; font-size: 16px; border: 1px solid #dfe1e5;
      border-radius: 24px; outline: none; }
    .search-input:focus { border-color: #4285f4; box-shadow: 0 1px 6px rgba(66,133,244,0.28); }
    .search-btn { margin-left: 8px; padding: 10px 20px; background: #4285f4; color: #fff;
      border: none; border-radius: 4px; cursor: pointer; font-size: 14px; }
    .search-btn:hover { background: #3367d6; }
    .nav-tabs { margin-top: 4px; }
    .nav-tabs a { display: inline-block; padding: 8px 16px; color: #70757a; text-decoration: none;
      font-size: 13px; border-bottom: 3px solid transparent; }
    .nav-tabs a.active { color: #1a73e8; border-bottom-color: #1a73e8; }
    .results { max-width: 750px; margin-left: 150px; padding: 20px 0; }
    .stats { color: #70757a; font-size: 13px; margin-bottom: 20px; }
    .did-you-mean { margin-bottom: 16px; font-size: 15px; }
    .did-you-mean a { color: #1a73e8; text-decoration: none; font-style: italic; }
    .result { margin-bottom: 28px; }
    .result-url { color: #202124; font-size: 14px; line-height: 1.3; }
    .result-url cite { color: #3c4043; font-style: normal; font-size: 13px; }
    .result-url .green-url { color: #188038; font-size: 13px; font-style: normal; }
    .result-title { display: block; }
    .result-title a { color: #1a0dab; font-size: 20px; text-decoration: none; line-height: 1.3; }
    .result-title a:hover { text-decoration: underline; }
    .result-title a:visited { color: #681da8; }
    .result-snippet { color: #4d5156; font-size: 14px; line-height: 1.58; margin-top: 4px; }
    .pagination { text-align: center; padding: 40px 0; }
    .pagination a, .pagination span {
      display: inline-block; margin: 0 4px; padding: 8px 14px; text-decoration: none;
      color: #1a73e8; font-size: 14px; border-radius: 4px; }
    .pagination span.current { background: #e8f0fe; color: #1a73e8; font-weight: bold; }
    .pagination a:hover { background: #f1f3f4; }
    .pagination .prev, .pagination .next { font-weight: bold; }
    .footer { background: #f2f2f2; border-top: 1px solid #e4e4e4; text-align: center;
      padding: 16px; color: #70757a; font-size: 13px; }
  </style>
</head>
<body>
  <div class="header">
    <div class="header-inner">
      <a href="/search" class="logo">
        <span>G</span><span>l</span><span>i</span><span>t</span><span>c</span><span>h</span>Search
      </a>
      <div class="search-bar">
        <form action="/search" method="get">
          <input class="search-input" type="text" name="q" value="`)
	htmlAttrEscape(&sb, query)
	sb.WriteString(`" autocomplete="off">
          <button class="search-btn" type="submit">Search</button>
        </form>
      </div>
      <div class="nav-tabs">
        <a href="/search?q=`)
	urlEscape(&sb, query)
	sb.WriteString(`" class="active">All</a>
        <a href="/search/images?q=`)
	urlEscape(&sb, query)
	sb.WriteString(`">Images</a>
      </div>
    </div>
  </div>
  <div class="results">
    <div class="stats">About `)
	sb.WriteString(formatNumber(totalResults))
	sb.WriteString(` results (`)
	sb.WriteString(fmt.Sprintf("%.2f", searchTime))
	sb.WriteString(` seconds)</div>
`)

	if didYouMean != "" {
		sb.WriteString(`    <div class="did-you-mean">Did you mean: <a href="/search?q=`)
		urlEscape(&sb, didYouMean)
		sb.WriteString(`">`)
		htmlEscape(&sb, didYouMean)
		sb.WriteString(`</a>?</div>
`)
	}

	for _, res := range results {
		sb.WriteString(`    <div class="result">
      <div class="result-url"><span class="green-url">`)
		htmlEscape(&sb, "glitchserver.local"+res.Path)
		sb.WriteString(`</span></div>
      <div class="result-title"><a href="`)
		htmlAttrEscape(&sb, res.Path)
		sb.WriteString(`">`)
		htmlEscape(&sb, res.Title)
		sb.WriteString(`</a></div>
      <div class="result-snippet">`)
		htmlEscape(&sb, res.Snippet)
		sb.WriteString(`</div>
    </div>
`)
	}

	// Pagination
	sb.WriteString(`    <div class="pagination">
`)
	if page > 1 {
		sb.WriteString(fmt.Sprintf(`      <a class="prev" href="/search?q=%s&page=%d">&laquo; Previous</a>`, urlEscapeStr(query), page-1))
		sb.WriteString("\n")
	}

	start := page - 4
	if start < 1 {
		start = 1
	}
	end := start + 9
	if end > totalPages {
		end = totalPages
	}

	for i := start; i <= end; i++ {
		if i == page {
			sb.WriteString(fmt.Sprintf(`      <span class="current">%d</span>`, i))
		} else {
			sb.WriteString(fmt.Sprintf(`      <a href="/search?q=%s&page=%d">%d</a>`, urlEscapeStr(query), i, i))
		}
		sb.WriteString("\n")
	}

	if page < totalPages {
		sb.WriteString(fmt.Sprintf(`      <a class="next" href="/search?q=%s&page=%d">Next &raquo;</a>`, urlEscapeStr(query), page+1))
		sb.WriteString("\n")
	}

	sb.WriteString(`    </div>
  </div>
  <div class="footer">
    <p>GlitchSearch &mdash; Searching the infinite labyrinth since 2024</p>
  </div>
</body>
</html>`)

	w.Write([]byte(sb.String()))
	return http.StatusOK
}

