// ---------------------------------------------------------------------------
// GET /search/images — image search results
// ---------------------------------------------------------------------------

func (h *Handler) serveImages(w http.ResponseWriter, r *http.Request) int {
	query := r.URL.Query().Get("q")
	if query == "" {
		query = "glitch"
	}

	rng := rand.New(rand.NewSource(querySeed(query)))

	// Generate 20 "image" results
	type imageResult struct {
		Title  string
		Width  int
		Height int
		Color1 string
		Color2 string
		Path   string
	}

	colors := []string{
		"#4285f4", "#ea4335", "#fbbc05", "#34a853", "#1a73e8",
		"#d93025", "#f9ab00", "#1e8e3e", "#5f6368", "#185abc",
		"#c5221f", "#e37400", "#137333", "#3c4043", "#174ea6",
		"#a50e0e", "#b06000", "#0d652d", "#80868b", "#1967d2",
	}

	images := make([]imageResult, 20)
	for i := range images {
		w2 := rng.Intn(400) + 200
		h2 := rng.Intn(300) + 150
		site := h.sites[rng.Intn(len(h.sites))]
		topic := h.topics[rng.Intn(len(h.topics))]
		images[i] = imageResult{
			Title:  fmt.Sprintf("%s - %s %s", query, h.adjectives[rng.Intn(len(h.adjectives))], h.nouns[rng.Intn(len(h.nouns))]),
			Width:  w2,
			Height: h2,
			Color1: colors[rng.Intn(len(colors))],
			Color2: colors[rng.Intn(len(colors))],
			Path:   fmt.Sprintf("/%s/%s", site, strings.ReplaceAll(topic, " ", "-")),
		}
	}

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.WriteHeader(http.StatusOK)

	var sb strings.Builder

	sb.WriteString(`<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>`)
	htmlEscape(&sb, query)
	sb.WriteString(` - GlitchSearch Images</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { font-family: Arial, sans-serif; background: #fff; color: #202124; }
    .header { background: #fff; border-bottom: 1px solid #dfe1e5; padding: 16px 20px; }
    .header-inner { display: flex; align-items: center; gap: 16px; max-width: 1200px; margin: 0 auto; }
    .logo a { color: #4285f4; text-decoration: none; font-size: 22px; font-weight: bold; }
    .search-bar form { display: flex; align-items: center; }
    .search-input { width: 500px; padding: 8px 14px; font-size: 14px; border: 1px solid #dfe1e5;
      border-radius: 24px; outline: none; }
    .search-input:focus { border-color: #4285f4; }
    .search-btn { margin-left: 8px; padding: 8px 16px; background: #4285f4; color: #fff;
      border: none; border-radius: 4px; cursor: pointer; font-size: 13px; }
    .nav-tabs { max-width: 1200px; margin: 0 auto; padding: 8px 20px; }
    .nav-tabs a { display: inline-block; padding: 6px 14px; color: #70757a; text-decoration: none;
      font-size: 13px; border-bottom: 3px solid transparent; }
    .nav-tabs a.active { color: #1a73e8; border-bottom-color: #1a73e8; }
    .grid { max-width: 1200px; margin: 20px auto; padding: 0 20px;
      display: grid; grid-template-columns: repeat(auto-fill, minmax(240px, 1fr)); gap: 16px; }
    .img-card { border: 1px solid #dfe1e5; border-radius: 8px; overflow: hidden; cursor: pointer;
      transition: box-shadow 0.2s; }
    .img-card:hover { box-shadow: 0 2px 8px rgba(0,0,0,0.15); }
    .img-card a { text-decoration: none; color: inherit; }
    .img-card svg { display: block; width: 100%; }
    .img-info { padding: 8px 10px; }
    .img-info .title { font-size: 13px; color: #202124; white-space: nowrap;
      overflow: hidden; text-overflow: ellipsis; }
    .img-info .size { font-size: 11px; color: #70757a; margin-top: 2px; }
    .footer { text-align: center; padding: 30px; color: #70757a; font-size: 13px;
      margin-top: 40px; border-top: 1px solid #e4e4e4; }
  </style>
</head>
<body>
  <div class="header">
    <div class="header-inner">
      <div class="logo"><a href="/search">GlitchSearch</a></div>
      <div class="search-bar">
        <form action="/search/images" method="get">
          <input class="search-input" type="text" name="q" value="`)
	htmlAttrEscape(&sb, query)
	sb.WriteString(`" autocomplete="off">
          <button class="search-btn" type="submit">Search</button>
        </form>
      </div>
    </div>
  </div>
  <div class="nav-tabs">
    <a href="/search?q=`)
	urlEscape(&sb, query)
	sb.WriteString(`">All</a>
    <a href="/search/images?q=`)
	urlEscape(&sb, query)
	sb.WriteString(`" class="active">Images</a>
  </div>
  <div class="grid">
`)

	for _, img := range images {
		// Render an SVG rectangle as the "image"
		sb.WriteString(`    <div class="img-card">
      <a href="`)
		htmlAttrEscape(&sb, img.Path)
		sb.WriteString(`">
        <svg viewBox="0 0 `)
		sb.WriteString(fmt.Sprintf(`%d %d`, img.Width, img.Height))
		sb.WriteString(`" xmlns="http://www.w3.org/2000/svg">
          <defs>
            <linearGradient id="g`)
		sb.WriteString(fmt.Sprintf("%d", img.Width*img.Height))
		sb.WriteString(`" x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" style="stop-color:`)
		sb.WriteString(img.Color1)
		sb.WriteString(`"/>
              <stop offset="100%" style="stop-color:`)
		sb.WriteString(img.Color2)
		sb.WriteString(`"/>
            </linearGradient>
          </defs>
          <rect width="100%" height="100%" fill="url(#g`)
		sb.WriteString(fmt.Sprintf("%d", img.Width*img.Height))
		sb.WriteString(`)"/>
          <text x="50%" y="50%" text-anchor="middle" dy=".3em"
            fill="rgba(255,255,255,0.6)" font-size="24" font-family="Arial">`)
		sb.WriteString(fmt.Sprintf("%dx%d", img.Width, img.Height))
		sb.WriteString(`</text>
        </svg>
        <div class="img-info">
          <div class="title">`)
		htmlEscape(&sb, img.Title)
		sb.WriteString(`</div>
          <div class="size">`)
		sb.WriteString(fmt.Sprintf("%d x %d", img.Width, img.Height))
		sb.WriteString(`</div>
        </div>
      </a>
    </div>
`)
	}

	sb.WriteString(`  </div>
  <div class="footer">GlitchSearch Images &mdash; Visual exploration of the infinite</div>
</body>
</html>`)

	w.Write([]byte(sb.String()))
	return http.StatusOK
}

// ---------------------------------------------------------------------------
// GET /api/search/suggest — JSON suggestion API
// ---------------------------------------------------------------------------

func (h *Handler) serveSuggest(w http.ResponseWriter, r *http.Request) int {
	query := r.URL.Query().Get("q")
	if query == "" {
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		w.Write([]byte("[]"))
		return http.StatusOK
	}

	rng := rand.New(rand.NewSource(querySeed(query)))

	numSuggestions := rng.Intn(6) + 5 // 5-10

	suggestions := make([]string, numSuggestions)
	lower := strings.ToLower(query)
	for i := range suggestions {
		suggestions[i] = h.generateSuggestion(rng, lower)
	}

	// Build JSON by hand to avoid encoding/json import (matching codebase style)
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)

	var sb strings.Builder
	sb.WriteString("[")
	for i, s := range suggestions {
		if i > 0 {
			sb.WriteString(",")
		}
		sb.WriteString(`"`)
		jsonStringEscape(&sb, s)
		sb.WriteString(`"`)
	}
	sb.WriteString("]")

	w.Write([]byte(sb.String()))
	return http.StatusOK
}

// ---------------------------------------------------------------------------
// result generation
// ---------------------------------------------------------------------------

type searchResult struct {
	Title   string
	Path    string
	Snippet string
}

func (h *Handler) generateResults(rng *rand.Rand, query string, count int) []searchResult {
	results := make([]searchResult, count)
	queryWords := strings.Fields(strings.ToLower(query))

	for i := range results {
		results[i] = h.generateOneResult(rng, queryWords)
	}
	return results
}

func (h *Handler) generateOneResult(rng *rand.Rand, queryWords []string) searchResult {
	// Pick a result style
	style := rng.Intn(6)

	var title, path, snippet string

	// Mix query words into the title
	topicWord := ""
	if len(queryWords) > 0 {
		topicWord = queryWords[rng.Intn(len(queryWords))]
	}

	adj := h.adjectives[rng.Intn(len(h.adjectives))]
	noun := h.nouns[rng.Intn(len(h.nouns))]
	topic := h.topics[rng.Intn(len(h.topics))]
	verb := h.verbs[rng.Intn(len(h.verbs))]
	site := h.sites[rng.Intn(len(h.sites))]

	switch style {
	case 0:
		title = fmt.Sprintf("The %s Guide to %s %s", adj, topicWord, noun)
		path = fmt.Sprintf("/%s/%s-%s", site, strings.ReplaceAll(topic, " ", "-"), slugify(topicWord))
		snippet = fmt.Sprintf("Learn how to %s %s %s with this %s resource. Covers everything from basics to %s %s, including real-world examples and best practices.",
			verb, adj, noun, adj, adj, noun)
	case 1:
		title = fmt.Sprintf("How to %s %s for %s | %s", strings.Title(verb), topicWord, topic, strings.Title(adj)+" Docs")
		path = fmt.Sprintf("/%s/%s/%s", site, slugify(topic), slugify(topicWord))
		snippet = fmt.Sprintf("Step-by-step instructions for %s %s in production %s. This %s guide explains the key %s and common pitfalls when working with %s.",
			verb+"ing", topicWord, noun, adj, noun, topic)
	case 2:
		title = fmt.Sprintf("%s vs %s: %s Comparison (%d)", strings.Title(topicWord), strings.Title(noun), strings.Title(adj), 2024+rng.Intn(3))
		path = fmt.Sprintf("/%s/compare/%s-vs-%s", site, slugify(topicWord), slugify(noun))
		snippet = fmt.Sprintf("Detailed comparison of %s and %s for %s. We analyzed %d %s across %d %s to help you choose the right %s for your needs.",
			topicWord, noun, topic, rng.Intn(50)+10, noun, rng.Intn(20)+5, noun, noun)
	case 3:
		title = fmt.Sprintf("%s %s Documentation - %s Reference", strings.Title(topicWord), strings.Title(noun), strings.Title(adj))
		path = fmt.Sprintf("/%s/%s/%s/reference", site, slugify(topicWord), slugify(noun))
		snippet = fmt.Sprintf("Official %s documentation for %s %s. Includes API reference, configuration %s, and %s %s for common use cases.",
			adj, topicWord, noun, noun, adj, noun)
	case 4:
		title = fmt.Sprintf("%s %s Tutorial: %s from Scratch", strings.Title(adj), strings.Title(topicWord), strings.Title(verb))
		path = fmt.Sprintf("/%s/tutorial/%s-%s", site, slugify(topicWord), slugify(verb))
		snippet = fmt.Sprintf("Master %s with this hands-on tutorial. You will learn to %s %s %s, %s %s, and deploy %s %s to production.",
			topicWord, verb, adj, noun, verb, noun, adj, noun)
	default:
		title = fmt.Sprintf("%d Best %s %s for %s", rng.Intn(20)+5, strings.Title(adj), strings.Title(noun), strings.Title(topicWord))
		path = fmt.Sprintf("/%s/best-%s-for-%s", site, slugify(noun), slugify(topicWord))
		snippet = fmt.Sprintf("Curated list of the top %s %s for %s in %d. Each %s has been tested for %s, %s, and overall %s performance.",
			adj, noun, topicWord, 2024+rng.Intn(3), noun, topic, adj, noun)
	}

	return searchResult{
		Title:   title,
		Path:    path,
		Snippet: snippet,
	}
}

func (h *Handler) generateSuggestion(rng *rand.Rand, prefix string) string {
	style := rng.Intn(8)
	topic := h.topics[rng.Intn(len(h.topics))]
	adj := h.adjectives[rng.Intn(len(h.adjectives))]
	noun := h.nouns[rng.Intn(len(h.nouns))]
	verb := h.verbs[rng.Intn(len(h.verbs))]

	switch style {
	case 0:
		return prefix + " " + topic
	case 1:
		return prefix + " " + adj + " " + noun
	case 2:
		return prefix + " tutorial"
	case 3:
		return prefix + " vs " + noun
	case 4:
		return "how to " + verb + " " + prefix
	case 5:
		return prefix + " best practices"
	case 6:
		return prefix + " " + noun + " guide"
	default:
		return prefix + " " + adj + " " + topic
	}
}

func (h *Handler) checkDidYouMean(query string) string {
	words := strings.Fields(strings.ToLower(query))
	corrected := make([]string, len(words))
	changed := false
	for i, w := range words {
		if fix, ok := h.typos[w]; ok {
			corrected[i] = fix
			changed = true
		} else {
			corrected[i] = w
		}
	}
	if changed {
		return strings.Join(corrected, " ")
	}
	return ""
}

// ---------------------------------------------------------------------------
// string helpers
// ---------------------------------------------------------------------------

func htmlEscape(sb *strings.Builder, s string) {
	for _, c := range s {
		switch c {
		case '<':
			sb.WriteString("&lt;")
		case '>':
			sb.WriteString("&gt;")
		case '&':
			sb.WriteString("&amp;")
		case '"':
			sb.WriteString("&quot;")
		default:
			sb.WriteRune(c)
		}
	}
}

func htmlAttrEscape(sb *strings.Builder, s string) {
	htmlEscape(sb, s)
}

func jsonStringEscape(sb *strings.Builder, s string) {
	for _, c := range s {
		switch c {
		case '"':
			sb.WriteString(`\"`)
		case '\\':
			sb.WriteString(`\\`)
		case '\n':
			sb.WriteString(`\n`)
		case '\r':
			sb.WriteString(`\r`)
		case '\t':
			sb.WriteString(`\t`)
		default:
			if c < 0x20 {
				sb.WriteString(fmt.Sprintf(`\u%04x`, c))
			} else {
				sb.WriteRune(c)
			}
		}
	}
}

func urlEscape(sb *strings.Builder, s string) {
	sb.WriteString(urlEscapeStr(s))
}

func urlEscapeStr(s string) string {
	var sb strings.Builder
	for i := 0; i < len(s); i++ {
		c := s[i]
		if isURLSafe(c) {
			sb.WriteByte(c)
		} else if c == ' ' {
			sb.WriteByte('+')
		} else {
			sb.WriteString(fmt.Sprintf("%%%02X", c))
		}
	}
	return sb.String()
}

func isURLSafe(c byte) bool {
	return (c >= 'A' && c <= 'Z') || (c >= 'a' && c <= 'z') ||
		(c >= '0' && c <= '9') || c == '-' || c == '_' || c == '.' || c == '~'
}

func slugify(s string) string {
	s = strings.ToLower(s)
	var sb strings.Builder
	for _, c := range s {
		if (c >= 'a' && c <= 'z') || (c >= '0' && c <= '9') {
			sb.WriteRune(c)
		} else if c == ' ' || c == '_' || c == '/' {
			sb.WriteByte('-')
		}
	}
	result := sb.String()
	// Collapse consecutive hyphens
	for strings.Contains(result, "--") {
		result = strings.ReplaceAll(result, "--", "-")
	}
	return strings.Trim(result, "-")
}

func formatNumber(n int) string {
	s := fmt.Sprintf("%d", n)
	if len(s) <= 3 {
		return s
	}
	var sb strings.Builder
	remainder := len(s) % 3
	if remainder > 0 {
		sb.WriteString(s[:remainder])
	}
	for i := remainder; i < len(s); i += 3 {
		if sb.Len() > 0 {
			sb.WriteByte(',')
		}
		sb.WriteString(s[i : i+3])
	}
	return sb.String()
}

func atoi(s string) int {
	n := 0
	neg := false
	i := 0
	if len(s) > 0 && s[0] == '-' {
		neg = true
		i = 1
	}
	for ; i < len(s); i++ {
		c := s[i]
		if c < '0' || c > '9' {
			break
		}
		n = n*10 + int(c-'0')
	}
	if neg {
		return -n
	}
	return n
}
